// Day Counter — calculate concluded week number and date range
function getWeekdayDates() {
  const dates = [];
  let d = new Date(Date.UTC(2026, 2, 2));
  while (dates.length < 90) {
    if (d.getUTCDay() !== 0 && d.getUTCDay() !== 6) dates.push(d.toISOString().split('T')[0]);
    d = new Date(d.getTime() + 86400000);
  }
  return dates;
}
const weekdays = getWeekdayDates();
const now = new Date();
const todayStr = now.toLocaleDateString('en-CA', { timeZone: 'Africa/Lagos' });

// On Sunday, find last weekday to determine concluded week
let lastWeekdayIdx = -1;
for (let i = weekdays.length - 1; i >= 0; i--) {
  if (weekdays[i] <= todayStr) { lastWeekdayIdx = i; break; }
}

const weekNum = lastWeekdayIdx >= 0 ? Math.ceil((lastWeekdayIdx + 1) / 5) : 1;
const weekStartIdx = (weekNum - 1) * 5;
const weekEndIdx = Math.min(weekNum * 5 - 1, weekdays.length - 1);
const mondayDate = weekStartIdx >= 0 ? weekdays[weekStartIdx] : todayStr;
const fridayDate = weekEndIdx >= 0 && weekEndIdx < weekdays.length ? weekdays[weekEndIdx] : todayStr;
const startDayNum = weekStartIdx + 1;
const endDayNum = weekEndIdx + 1;

return [{ json: { week_num: weekNum, monday_date: mondayDate, friday_date: fridayDate, start_day_num: startDayNum, end_day_num: endDayNum, date: todayStr } }];

// Weekly Stats — aggregate scores and disciplines
const logs = $('Get Weekly Logs').all().map(i => i.json);
const weekLogs = logs.length > 0 && Array.isArray(logs[0]) ? logs[0] : logs;
const dayCounter = $('Day Counter').first().json;

let totalScore = 0, prayerSessions = 0, ntChapters = 0, bookPages = 0;
let codeHrs = 0, proposalsSent = 0, revenueEarned = 0, videosPublished = 0;
let bestDay = { num: 0, score: -1 };
let worstDay = { num: 0, score: 101 };
let daysWithData = 0;
const dayScores = [];

for (const log of weekLogs) {
  if (!log || !log.day_num) continue;
  daysWithData++;
  const score = log.day_score || 0;
  totalScore += score;
  dayScores.push({ day: log.day_num, date: log.day_date || '', score });
  if (log.prayer_s1) prayerSessions++;
  if (log.prayer_s2) prayerSessions++;
  ntChapters += (log.nt_chapters_read || 0);
  bookPages += (log.book_pages || 0);
  codeHrs += (log.code_hrs || 0);
  proposalsSent += (log.proposals_sent || 0);
  revenueEarned += (log.revenue_today || 0);
  videosPublished += (log.videos_published || 0);
  if (score > bestDay.score) bestDay = { num: log.day_num, score };
  if (score < worstDay.score) worstDay = { num: log.day_num, score };
}

const avgScore = daysWithData > 0 ? Math.round(totalScore / daysWithData) : 0;
const weekNum = dayCounter.week_num;
let phase = 1, weeklyTarget = 1000;
if (weekNum >= 9) { phase = 3; weeklyTarget = 20000; }
else if (weekNum >= 5) { phase = 2; weeklyTarget = 5000; }

const dateRange = dayCounter.monday_date + ' to ' + dayCounter.friday_date;
const subject = 'War Plan · Week ' + weekNum + ' Concluded — ' + avgScore + '% average · $' + revenueEarned + ' earned';

return [{ json: {
  week_num: weekNum, date_range: dateRange, avg_score: avgScore,
  days_with_data: daysWithData, prayer_sessions: prayerSessions,
  nt_chapters: ntChapters, book_pages: bookPages,
  code_hrs: Math.round(codeHrs * 10) / 10,
  proposals_sent: proposalsSent, revenue_earned: revenueEarned,
  videos_published: videosPublished, best_day: bestDay, worst_day: worstDay,
  day_scores: dayScores, phase, weekly_target: weeklyTarget, subject
} }];

